// ============================================
// ROTATE & SEND TEXT — Auto-Discovery + Failover
// ============================================
// Uses require('http') — n8n sandbox has no global fetch/URL
// ============================================

const http = require('http');

// --- CONFIG ---
const EVO_HOST = 'host.docker.internal';
const EVO_PORT = 8080;
const EVO_API_KEY = 'fa67ff482194dac60c4ffa0733a83d43cc540ce9';
// --- END CONFIG ---

function httpReq(path, method, headers, body) {
  return new Promise((resolve, reject) => {
    const opts = {
      hostname: EVO_HOST, port: EVO_PORT,
      path: path, method: method || 'GET',
      headers: headers || {}
    };
    const req = http.request(opts, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        let json;
        try { json = JSON.parse(data); } catch (e) { json = {}; }
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, statusCode: res.statusCode, statusText: res.statusMessage, data: json });
      });
    });
    req.on('error', reject);
    if (body) req.write(typeof body === 'string' ? body : JSON.stringify(body));
    req.end();
  });
}

const raw = $input.first().json;
const body = raw.body || raw;
const phone = body.phone;
const message = body.message;

// 1. Fetch semua instance (auto-discovery)
let instancesRaw;
try {
  const res = await httpReq('/instance/fetchInstances', 'GET', { 'apikey': EVO_API_KEY });
  instancesRaw = res.data;
} catch (err) {
  return [{ json: {
    success: false,
    error: 'Gagal connect ke Evolution API: ' + String(err.message || err),
    instanceUsed: null, connectedInstances: [], totalInstances: 0
  }}];
}

// 2. Filter connected instances
const connected = [];
if (Array.isArray(instancesRaw)) {
  for (const inst of instancesRaw) {
    const name = inst.name || (inst.instance && inst.instance.instanceName) || inst.instanceName;
    const status = inst.connectionStatus || (inst.instance && inst.instance.status) || inst.status;
    if (status === 'open' && name) connected.push(name);
  }
}

if (connected.length === 0) {
  const total = Array.isArray(instancesRaw) ? instancesRaw.length : 0;
  return [{ json: {
    success: false,
    error: 'Tidak ada WhatsApp instance yang terhubung (' + total + ' ditemukan). Scan QR dulu.',
    instanceUsed: null, connectedInstances: [], totalInstances: 0
  }}];
}

// 3. Round-robin
const staticData = $getWorkflowStaticData('global');
const lastIdx = typeof staticData.lastInstanceIndex === 'number' ? staticData.lastInstanceIndex : -1;
const startIdx = (lastIdx + 1) % connected.length;

// 4. Send text with failover
let success = false;
let usedInstance = '';
let lastError = '';
const attempts = [];

for (let i = 0; i < connected.length; i++) {
  const idx = (startIdx + i) % connected.length;
  const instanceName = connected[idx];

  try {
    const sendRes = await httpReq(
      '/message/sendText/' + instanceName,
      'POST',
      { 'Content-Type': 'application/json', 'apikey': EVO_API_KEY },
      JSON.stringify({ number: phone, text: message })
    );

    if (sendRes.ok && !sendRes.data.error) {
      success = true;
      usedInstance = instanceName;
      staticData.lastInstanceIndex = idx;
      attempts.push({ instance: instanceName, status: 'ok' });
      break;
    } else {
      const errMsg = sendRes.data.error || sendRes.data.message || sendRes.statusText;
      attempts.push({ instance: instanceName, status: 'failed', error: errMsg });
      lastError = instanceName + ': ' + errMsg;
    }
  } catch (err) {
    const errMsg = String(err.message || err);
    attempts.push({ instance: instanceName, status: 'error', error: errMsg });
    lastError = instanceName + ': ' + errMsg;
  }
}

if (!success) {
  return [{ json: {
    success: false,
    error: 'Semua instance gagal (' + connected.length + ' dicoba). Error: ' + lastError,
    attempts, connectedInstances: connected, totalInstances: connected.length, instanceUsed: null
  }}];
}

return [{ json: {
  success: true,
  instanceUsed: usedInstance,
  connectedInstances: connected,
  totalInstances: connected.length,
  attempts, phone,
  pdfBase64: body.pdfBase64 || '',
  fileName: body.fileName || ''
}}];

// ============================================
// SEND PDF — via instance yang berhasil kirim teks
// ============================================

const http = require('http');

const EVO_HOST = 'host.docker.internal';
const EVO_PORT = 8080;
const EVO_API_KEY = 'fa67ff482194dac60c4ffa0733a83d43cc540ce9';

function httpReq(path, method, headers, body) {
  return new Promise((resolve, reject) => {
    const opts = {
      hostname: EVO_HOST, port: EVO_PORT,
      path: path, method: method || 'GET',
      headers: headers || {}
    };
    const req = http.request(opts, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        let json;
        try { json = JSON.parse(data); } catch (e) { json = {}; }
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, statusCode: res.statusCode, statusText: res.statusMessage, data: json });
      });
    });
    req.on('error', reject);
    if (body) req.write(typeof body === 'string' ? body : JSON.stringify(body));
    req.end();
  });
}

const data = $input.first().json;
const instanceName = data.instanceUsed;
const phone = data.phone;
const pdfBase64 = data.pdfBase64;
const fileName = data.fileName || 'Invoice.pdf';

try {
  const res = await httpReq(
    '/message/sendMedia/' + instanceName,
    'POST',
    { 'Content-Type': 'application/json', 'apikey': EVO_API_KEY },
    JSON.stringify({ number: phone, mediatype: 'document', media: pdfBase64, fileName: fileName })
  );

  if (res.ok && !res.data.error) {
    return [{ json: {
      success: true,
      message: 'WhatsApp terkirim dengan PDF',
      instanceUsed: instanceName,
      connectedInstances: data.connectedInstances,
      totalInstances: data.totalInstances
    }}];
  } else {
    return [{ json: {
      success: true,
      message: 'Teks terkirim, PDF gagal: ' + (res.data.error || res.statusText),
      instanceUsed: instanceName,
      connectedInstances: data.connectedInstances,
      totalInstances: data.totalInstances
    }}];
  }
} catch (err) {
  return [{ json: {
    success: true,
    message: 'Teks terkirim, PDF error: ' + String(err.message || err),
    instanceUsed: instanceName,
    connectedInstances: data.connectedInstances,
    totalInstances: data.totalInstances
  }}];
}
